analizá: def ordenar(xs):
    for i in range(len(xs)):
        for j in range(len(xs)-1):
            if xs[j] > xs[j+1]:
                xs[j], xs[j+1] = xs[j+1], xs[j]
    return xs

analizá: def pares(xs):
    r = []
    for a in xs:
        for b in xs:
            r.append((a, b))
    return r

analizá: def suma(n):
    if n == 0:
        return 0
    return n + suma(n-1)
